+    } else {
+      EXPECT_EQ("/foo/bar/baz", p.string());
+    }
+  }
+  {
+    auto p = path("\\foo\\bar\\baz");
+    if (is_win32) {
+      EXPECT_EQ("\\foo\\bar\\baz", p.string());
+    } else {
+      EXPECT_EQ("/foo/bar/baz", p.string());
+    }
+  }
+  {
+    auto p = path("/foo//bar/baz");
+    if (is_win32) {
+      EXPECT_EQ("\\foo\\\\bar\\baz", p.string());
+    } else {
+      EXPECT_EQ("/foo//bar/baz", p.string());
+    }
+  }
+  {
+    auto p = path("\\foo\\\\bar\\baz");
+    if (is_win32) {
+      EXPECT_EQ("\\foo\\\\bar\\baz", p.string());
+    } else {
+      EXPECT_EQ("/foo//bar/baz", p.string());
+    }
+  }
