+{
+  if (is_win32) {
+    {
+      auto p = path("C:\\foo\\bar\\baz");
+      EXPECT_TRUE(p.is_absolute());
+    }
+    {
+      auto p = path("D:\\foo\\bar\\baz");
+      EXPECT_TRUE(p.is_absolute());
+    }
+    {
+      auto p = path("C:/foo/bar/baz");
+      EXPECT_TRUE(p.is_absolute());
+    }
+    {
+      auto p = path("foo/bar/baz");
+      EXPECT_FALSE(p.is_absolute());
+    }
+  } else {
+    {
+      auto p = path("/foo/bar/baz");
+      EXPECT_TRUE(p.is_absolute());
+    }
+    {
+      auto p = path("foo/bar/baz");
+      EXPECT_FALSE(p.is_absolute());
+    }
