+  // tests CAPABILITY
+  FakeGuarded guarded;
+
+  // tests ACQUIRE
+  guarded.mu.lock();
+
+  // tests GUARDED_BY
+  guarded.data++;
+
+  // tests REQUIRES
+  guarded.incr_HaveGuard();
+
+  // tests ASSERT_CAPABILITY
+  guarded.mu.assertHeld();
