+  EXPECT_EQ(rcppmath::clamp(2, 2, 5, cmp), 2);
+  EXPECT_EQ(rcppmath::clamp(5, 2, 5, cmp), 5);
+  EXPECT_EQ(rcppmath::clamp(6, 2, 5, cmp), 5);
